//! The target-agnostic perception `Frame` — packed RGB24 + index/pts/dims.
//!
//! The perception core (`vision`, `cadence`'s per-frame work) consumes frames; it does NOT
//! decode them. Native builds get frames from `frffmpeg::decode` (ffmpeg or the raw RGB24
//! `RawFrameSource`); the wasm build gets them written in-place into a `PerceptionEngine`
//! frame buffer by the host (zero-copy). Either way the perception math sees the SAME struct.
//!
//! This severs the one core→`frffmpeg` edge (`vision.rs` previously imported
//! `frffmpeg::decode::Frame`). On native we keep an infallible `From<frffmpeg::decode::Frame>`
//! so the bin/cadence decode path is unchanged; on wasm `frffmpeg` is not even compiled.
//!
//! Field-for-field identical to `frffmpeg::decode::Frame` (`frffmpeg/src/decode.rs:38-49`),
//! so the conversion is a move with no per-field copy of the `rgb` buffer.

/// One perception frame: packed RGB24, plus index and presentation time.
#[derive(Clone)]
pub struct Frame {
    /// 0-based index in the (post-downsample) stream.
    pub index: u64,
    /// Presentation time in seconds.
    pub pts_s: f64,
    pub width: u32,
    pub height: u32,
    /// Packed RGB24, len == width*height*3, stride == width*3.
    pub rgb: Vec<u8>,
}

impl std::fmt::Debug for Frame {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("Frame")
            .field("index", &self.index)
            .field("pts_s", &self.pts_s)
            .field("width", &self.width)
            .field("height", &self.height)
            .field("rgb_len", &self.rgb.len())
            .finish()
    }
}

/// Native bridge: the `frffmpeg` decoder yields `frffmpeg::decode::Frame`; the core wants the
/// local `Frame`. The `rgb` buffer is MOVED (no copy of the ~390KB payload).
#[cfg(not(target_arch = "wasm32"))]
impl From<frffmpeg::decode::Frame> for Frame {
    fn from(f: frffmpeg::decode::Frame) -> Self {
        Frame { index: f.index, pts_s: f.pts_s, width: f.width, height: f.height, rgb: f.rgb }
    }
}
